import React from 'react';

const Footer = () => {
  return (
    <footer className="mt-20 py-10 border-t border-white/10 bg-black/20 backdrop-blur-md">
      <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="text-gray-400 text-sm">
          © 2026 TASK.IO. All Rights Reserved. | Developed by <span className="text-white font-bold">Aditya Kumar</span>
        </div>
        <div className="flex gap-6 text-gray-400 text-sm">
          <a href="mailto:adityak12322@gmail.com" className="hover:text-purple-400">Email</a>
          <a href="#" className="hover:text-purple-400">LinkedIn</a>
          <a href="#" className="hover:text-purple-400">Github</a>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
